fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    let mut prefix = vec![0; n + 1];
    for i in 1..=n {
        prefix[i] = prefix[i - 1] + nums[i - 1];
    }
    let mut dp = vec![0; n + 1];
    let mut first_occurrence = HashMap::new();
    first_occurrence.insert(0, 0);
    for i in 1..=n {
        let current_remainder = prefix[i] % k;
        if first_occurrence.contains_key(&current_remainder) {
            let j = first_occurrence[&current_remainder];
            let candidate = dp[j as usize] + (prefix[i] - prefix[j as usize]);
            dp[i as usize] = std::cmp::max(dp[i as usize - 1], candidate);
