function solve(nums, k) {
    let n = nums.length;
    let prefix = [0];
    for (let i = 0; i < n; i++) {
        prefix.push(prefix[i] + nums[i]);
    }
    let dp = new Array(n + 1).fill(0);
    let first_occurrence = new Map();
    first_occurrence.set(0, 0);

    for (let i = 1; i <= n; i++) {
        let current_remainder = prefix[i] % k;
        if (first_occurrence.has(current_remainder)) {
            let j = first_occurrence.get(current_remainder);
            let candidate = dp[j] + (prefix[i] - prefix[j]);
            dp[i] = Math.max(dp[i - 1], candidate);
        } else {
            dp[i] = dp[i - 1];
        }
        if (!first_occurrence.has(current_remainder)) {
            first_occurrence.set(current_remainder, i);
        }
    }
    return prefix[n] - dp[n];
}
